import React from 'react'
import {useState} from 'react'

function App() {

  const [count, setCount] = useState(0);

  function increase()
  {
    setCount(count+1);
  }  

  function decrease()
  {
    setCount(count-1);
  }

  return (
    <>
    <p> Count: {count}</p>
    <button onClick={()=>{count < 10 ? increase(): alert("no")}}>count++</button>
    <button onClick={()=>{count > 0 ? decrease(): alert("no")}}>count--</button>
    </>
  )
}

export default App